import{_ as t,o as e,c as o,a2 as i}from"./chunks/framework.gSjTt1Hm.js";const g=JSON.parse('{"title":"什么是 FWP","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-fwp.md","filePath":"guide/what-is-fwp.md","lastUpdated":1783864095000}'),l={name:"guide/what-is-fwp.md"};function s(r,a,n,p,d,h){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="什么是-fwp" tabindex="-1">什么是 FWP <a class="header-anchor" href="#什么是-fwp" aria-label="Permalink to &quot;什么是 FWP&quot;">​</a></h1><p><strong>Fiammetta Watcher Proxy</strong>（简称 FWP）是一个开源的多平台 AI API 代理网关。</p><h2 id="为什么需要-fwp" tabindex="-1">为什么需要 FWP？ <a class="header-anchor" href="#为什么需要-fwp" aria-label="Permalink to &quot;为什么需要 FWP？&quot;">​</a></h2><p>当你使用多个 AI 平台（OpenAI、Anthropic、Google 等）时，会遇到以下问题：</p><ul><li>每个平台有不同的 API 格式和认证方式</li><li>需要分别管理多个 API Key</li><li>无法统一监控各平台的用量和成本</li><li>某个平台故障时需要手动切换</li></ul><p><strong>FWP 解决了这些问题</strong>：它提供一个统一的入口，将请求智能路由到不同的后端平台。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 → FWP → OpenAI / Anthropic / Google / ...</span></span></code></pre></div><ul><li><strong>平台（Platform）</strong>：后端 AI 服务提供商</li><li><strong>API Key</strong>：客户端用来认证的密钥</li><li><strong>模型映射（Model Map）</strong>：将一个模型名映射到另一个模型名</li><li><strong>代理池（Proxy Pool）</strong>：用于访问平台的 HTTP 代理集合</li><li><strong>套餐（Plan）</strong>：定义 Key 的配额和限制</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2>',10)])])}const u=t(l,[["render",s]]);export{g as __pageData,u as default};
